CODE_EXAMPLE:
// Pure business logic — no threading knowledge
class ItemProcessor {
    public Result process(Item item) {
        // domain logic only
        return new Result(item.getValue() * 2);
    }
}

// Concurrency concern isolated here
class ConcurrentProcessingService {
    private final ItemProcessor processor;
    private final ExecutorService pool;

    public ConcurrentProcessingService(ItemProcessor processor, int threads) {
        this.processor = processor;
        this.pool = Executors.newFixedThreadPool(threads);
    }

    public List<Future<Result>> processAll(List<Item> items) {
        return items.stream()
            .map(item -> pool.submit(() -> processor.process(item)))
            .collect(toList());
    }
}

UNIT_TEST_EXAMPLE:
@Test
public void process_returnsDoubledValue() {
    // Business logic tested without any threading
    ItemProcessor processor = new ItemProcessor();
    Result result = processor.process(new Item(5));
    assertEquals(10, result.getValue());
}
